    'hand', 'eyes', 'lips', 'voice', 'gaze', 'thought', 'memory', 'scene', 'world', 'rule',
    'character', 'person', 'entity', 'relation', 'relationship', 'people',
    '彼', '彼女', '彼ら', '誰か', '何か', 'これ', 'それ', 'あれ', '状態', '感情', '空気', '雰囲気',
    '手', '目', '瞳', '唇', '肩', '声', '視線', '考え', '思考', '記憶', '場面', '世界', '規則',
    'キャラクター', '人物', '人', '関係', '関係性'
